name = #{name}, project_id = #{projectId}, project_name = #{projectName}, assignee = #{assignee}, plan_start_date = #{planStartDate}, plan_end_date = #{planEndDate}, actual_launch_date = #{actualLaunchDate}, status = #{status}, priority = #{priority},
